void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

// DISCO BALL TEXTURES EDITED BY JIAN SIMANJUNTAK //
float z = q30;
float d = q31;
float pi = q28;
float pi2inv = q29;
float mask_apex = q32;
float zoom = q27;

vec2 c = zoom*(vUv-0.5)*uAspect.xy;

float camera_apex = atan( length(c),z);

bool mask = mask_apex >= camera_apex;

float longitude = atan(c.x,c.y);
float latitude = (pi - camera_apex + asin(d*sin(camera_apex)));

vec2 polar = vec2(longitude,latitude);

vec3 p = vec3( sin(polar.x)*sin(polar.y),cos(polar.x)*sin(polar.y),cos(polar.y));

factorA = p.zy;
factorB = vec2(q20,q21);
product = cmul(factorA,factorB);
p.zy = product.xy;

factorA = p.zx;
factorB = vec2(q22,q23);
product = cmul(factorA,factorB);
p.zx = product.xy;

vec3 cp = p;
factorA = cp.zx;
factorB = vec2(q11,q12);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y,factorA.x*factorB.y + factorA.y*factorB.x);
cp.zx = product.xy;

vec2 cpolar = polar;
vec2 cpolars = polar;
polar = vec2(atan(p.z,p.x),atan(p.y,length(p.xz)))*pi2inv*vec2(1,2)+vec2(0,0.5);
cpolar = vec2(atan(cp.z,cp.x),atan(cp.y,length(cp.xz)))*pi2inv*vec2(1,2)+vec2(0,0.5);
cp = cp+0.01;
cpolars = vec2(atan(cp.z,cp.x),atan(cp.y,length(cp.xz)))*pi2inv*vec2(1,2)+vec2(0,0.5);
// END //

    float rad_lq = vRadius * length(uTexSize.xy)*0.5;
    float ang_lq = vAngle;
    vec2 uv_temp1 = (vUv - 0.5) * uTexSize.xy;
    float rad_hq = length(uv_temp1);
    float ang_hq = atan(-uv_temp1.y, uv_temp1.x);

    vec2 uv2 = (vUv - 0.5);
    float rad2 = rad_lq*0.8;
    float ang2 = ang_lq * M_INV_PI_2 + rad_lq*0.000 + uTime*0.08;


        // FIN TYPE
        float fins = 16;
        ang2 = fract(ang2*fins)/fins;
              // ENABLE THIS TO MAKE THE FINS ALTERNATE: (seamless!)
              ang2 = abs(ang2 - q2/fins);


    ang2 *= M_PI_2;
    vec2 uv_kal = 0.5 + rad2*vec2(cos(ang2),sin(ang2))*uTexSize.zw;

    ret = texture(sampler_main, uv_kal).xyz*1 +
              GetBlur1(uv_kal)*3 +
              GetBlur2(uv_kal)*0 +
              GetBlur3(uv_kal)*0 +
              0;
    ret += GetBlur2( (uv_kal-0.5)*0.333 + 0.5);
    ret *= 1;



vUv *= uAspect.xy;
float uv_ball = lum(texture( sampler_disco_lights, mask*polar));

if (uv_ball > .007 && audioLow+audioMid+audioHigh) //Se7enSlasher - Added a functionality to not appear the texture when there's no music.
   { ret = mask*texture(sampler_disco_lights, polar)*(audioLowSmooth*1.2); }

// Thank you for edited by Jian Simanjuntak //

  fragColor = ret;
}
